args.query:
SELECT ch.oldvalue__c AS from_owner, ch.newvalue__c AS to_owner, ch.createddate
FROM casehistory__c ch
WHERE ch.field__c = 'Owner' AND ch.createddate >= '2022-04-10' AND ch.createddate < '2023-04-11';

